-- ПОЛНЫЙ SQL ЗАПРОС ДЛЯ ИМПОРТА ДАННЫХ ГАРДЕРОБА В SUPABASE
-- Этот файл содержит всё необходимое для создания таблицы и вставки данных

-- Шаг 1: Создаем таблицу
DROP TABLE IF EXISTS wardrobe_items CASCADE;

CREATE TABLE wardrobe_items (
    id BIGSERIAL PRIMARY KEY,
    item_name TEXT NOT NULL,
    item_type TEXT,
    size_type TEXT,
    material TEXT,
    style TEXT,
    has_print TEXT,
    color TEXT,
    shade TEXT,
    has_details TEXT,
    url TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Шаг 2: Создаем индексы для быстрого поиска
CREATE INDEX idx_wardrobe_items_name ON wardrobe_items(item_name);
CREATE INDEX idx_wardrobe_items_type ON wardrobe_items(item_type);
CREATE INDEX idx_wardrobe_items_color ON wardrobe_items(color);
CREATE INDEX idx_wardrobe_items_material ON wardrobe_items(material);

-- Шаг 3: Настраиваем безопасность (RLS)
ALTER TABLE wardrobe_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow all operations for authenticated users" ON wardrobe_items
    FOR ALL USING (auth.role() = 'authenticated');

CREATE POLICY "Allow read for anonymous users" ON wardrobe_items
    FOR SELECT USING (auth.role() = 'anon');

-- Шаг 4: Вставляем все данные из CSV

-- Шаг 5: Проверяем результат
SELECT COUNT(*) as total_items FROM wardrobe_items;
SELECT * FROM wardrobe_items LIMIT 5;
SELECT item_type, COUNT(*) as count FROM wardrobe_items GROUP BY item_type ORDER BY count DESC;
